// ========== PASSWORD & AUTHENTICATION ==========
const DEFAULT_PW_HASH = '3f04f50dff417df0413038238e61553c6409ac30b2eca4201e887e00f8fa34ec';
async function hashPw(pw){
  const buf=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(pw));
  return Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
}
function getPwHash(){return localStorage.getItem('pf_pw_hash')||DEFAULT_PW_HASH;}

// ========== LANGUAGE & TRANSLATION ==========
// Mehrsprachige UI-Unterstützung (Deutsch & Englisch)
let lang = localStorage.getItem('pf_lang')||'de';
const UI = {
  de:{back:'← zurück',upcoming:'Termine',past:'Vergangene Veranstaltungen',noProjects:'Noch keine Projekte.',foto:'foto',cfTitle:'Nachricht senden',cfName:'Dein Name',cfEmail:'E-Mail',cfSubject:'Betreff',cfMsg:'Nachricht',cfSend:'Senden',cfFill:'Bitte E-Mail und Nachricht ausfüllen.',cfOpen:'Dein Mail-Programm wird geöffnet…'},
  en:{back:'← back',upcoming:'Upcoming Events',past:'Past Events',noProjects:'No projects yet.',foto:'photo',cfTitle:'Send a message',cfName:'Your name',cfEmail:'E-Mail',cfSubject:'Subject',cfMsg:'Message',cfSend:'Send',cfFill:'Please fill in your email and message.',cfOpen:'Your email client will open…'}
};
function t(k){return(UI[lang]||UI.de)[k]||k;}
function L(o){if(!o)return'';if(typeof o==='string')return o;return o[lang]||o.de||'';}
function setLang(l){
  lang=l;localStorage.setItem('pf_lang',l);
  document.documentElement.lang=l;
  document.querySelectorAll('.lang-btn').forEach(b=>b.classList.toggle('active',b.textContent===l.toUpperCase()));
  const hint=document.getElementById('splash-hint');
  if(hint)hint.textContent=l==='en'?'click to enter':'klicken um einzutreten';
  applyLangUI();
  buildNav();
  // Re-render the currently active view immediately
  if(currentSection==="home"){renderHomeText();renderHomeBg();renderCircles();}
  else if(currentSection==='termine'){renderTermineView();}
  else if(currentSection==='bio'){renderBio();}
  else if(currentSection==='kontakt'){renderKontakt();}
  else if(currentSection==='project'){
    const bb=document.getElementById('back-btn');if(bb)bb.textContent=t('back');
    // Re-render project content with new lang
    const viewEl=document.getElementById('view-project');
    if(viewEl&&viewEl._sectionId!==undefined)renderProject(viewEl._sectionId,viewEl._projectIdx);
  }
  else if(currentSection){renderSectionList(currentSection);}
  // Sync header text
  document.getElementById('header-name').textContent=data.name||'';
  document.getElementById('header-sub').textContent=L(data.sub)||'';
  document.getElementById('footer-text').textContent=data.footer||'© 2026';
  document.querySelectorAll('.lang-btn').forEach(b=>b.classList.toggle('active',b.textContent===l.toUpperCase()));
}

// HILFSFUNKTIONEN
function escH(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function migrateData(d){
  if(!d.contactLinks)d.contactLinks=[];
  if(!d.events)d.events=[];
  if(!d.sections)d.sections=defaultSections();
  if(!d.sectionMedia)d.sectionMedia={};
  if(!d.sectionBg)d.sectionBg={};
  if(!d.eventsImage)d.eventsImage={url:'',active:false};
  if(!d.homeBg)d.homeBg={url:'',active:false,posX:'50',posY:'50',opacity:1,glowStrength:70};
  // Migrate legacy eventsImage into homeBg
  if(!d.homeBg.url&&d.eventsImage&&d.eventsImage.url){
    d.homeBg.url=d.eventsImage.url;
    d.homeBg.active=d.eventsImage.active||false;
  }
  if(!d.splashAudio)d.splashAudio={source:'tracks',bandcampSrc:'',soundcloudSrc:'',active:false};
  if(!d.splashAudio.tracks)d.splashAudio.tracks=[];
  if(d.splashAudio.source===undefined)d.splashAudio.source='tracks';
  if(!d.soundCircles)d.soundCircles=[];
  if(!d.bioBg)d.bioBg={url:'',active:false,opacity:1,glowStrength:70};
  if(!d.kontaktBg)d.kontaktBg={url:'',active:false,opacity:1,glowStrength:70};
  // Termine als eigene Rubrik
  const hasTermine=(d.sections||[]).find(s=>s.id==='termine');
  if(!hasTermine){
    const bioIdx=(d.sections||[]).findIndex(s=>s.type==='bio');
    const ins={id:'termine',label:{de:'termine',en:'dates'},type:'termine'};
    if(bioIdx>-1)d.sections.splice(bioIdx,0,ins);
    else d.sections.push(ins);
  }
  if(typeof d.homeText==='string')d.homeText={de:d.homeText,en:''};
  if(typeof d.sub==='string')d.sub={de:d.sub,en:''};
  if(d.bio&&typeof d.bio.text==='string')d.bio.text={de:d.bio.text,en:''};
  (d.sections||[]).forEach(s=>{
    if(typeof s.label==='string')s.label={de:s.label,en:s.label};
    if(s.type==='projects'&&!d.projects[s.id])d.projects[s.id]=[];
  });
  Object.values(d.projects||{}).forEach(arr=>(arr||[]).forEach(p=>{
    if(typeof p.title==='string')p.title={de:p.title,en:''};
    if(typeof p.desc==='string')p.desc={de:p.desc,en:''};
    if(!p.shortDesc)p.shortDesc={de:'',en:''};
    if(typeof p.tags==='string')p.tags={de:p.tags,en:p.tags};
    if(p.bgImg===undefined)p.bgImg='';
  }));
  (d.events||[]).forEach(ev=>{if(typeof ev.title==='string')ev.title={de:ev.title,en:ev.title};});
  // Ensure sectionBg opacity/glow defaults
  Object.values(d.sectionBg||{}).forEach(sb=>{
    if(sb.opacity===undefined)sb.opacity=0.5;
    if(sb.glowStrength===undefined)sb.glowStrength=70;
  });
  return d;
}
function defaultSections(){return[
  {id:'musik',label:{de:'sound',en:'sound'},type:'projects'},
  {id:'theater',label:{de:'theater',en:'theatre'},type:'projects'},
  {id:'visuelles',label:{de:'visuelles',en:'visual'},type:'projects'},
  {id:'termine',label:{de:'termine',en:'dates'},type:'termine'},
  {id:'bio',label:{de:'bio',en:'bio'},type:'bio'},
  {id:'kontakt',label:{de:'kontakt',en:'contact'},type:'kontakt'}
];}

// ========== MEDIA & RENDERING FUNCTIONS ==========
// Stoppt alle Audio/Video-Embedded-Elemente und hält nur ein Audio aktiv
function stopAllMedia(){
  document.querySelectorAll('audio').forEach(a=>{try{a.pause();}catch(e){}}
  );
  document.querySelectorAll('.sound-circle.expanded').forEach(el=>_collapseCdEl(el));
  document.querySelectorAll('iframe').forEach(f=>{
    const src=(f.src||'').toLowerCase();
    if(src.includes('w.soundcloud.com/player')||src.includes('soundcloud.com/player')||src.includes('bandcamp.com')||src.includes('youtube.com/embed')||src.includes('player.vimeo.com')||f.id==='splash-audio-frame'){
      try{f.contentWindow.postMessage(JSON.stringify({method:'pause'}),'*');}catch(e){}
      try{f.contentWindow.postMessage(JSON.stringify({method:'stop'}),'*');}catch(e){}
      try{f.contentWindow.postMessage(JSON.stringify({event:'command',func:'pauseVideo',args:''}),'*');}catch(e){}
    }
  });
  const splashFrame=document.getElementById('splash-audio-frame');
  if(splashFrame){
    try{splashFrame.contentWindow.postMessage(JSON.stringify({method:'pause'}),'*');}catch(e){}
  }
  if(splashAudio&&splashAudio.tagName==='AUDIO'){
    try{splashAudio.pause();}catch(e){}
  }
}

function setIframeVolume(iframe,vol){
  try{iframe.contentWindow.postMessage(JSON.stringify({method:'setVolume',value:Math.round(vol*100)}),'*');}catch(e){}
}

function applyVolume(vol){
  document.querySelectorAll('audio').forEach(a=>{try{a.volume=vol;}catch(e){}});
  document.querySelectorAll('iframe').forEach(f=>{
    const src=(f.src||'').toLowerCase();
    if(src.includes('w.soundcloud.com/player')||src.includes('soundcloud.com/player')||src.includes('bandcamp.com/embeddedplayer')||f.id==='splash-audio-frame'){
      setIframeVolume(f,vol);
    }
  });
  if(splashAudio&&splashAudio.tagName==='AUDIO'){
    try{splashAudio.volume=vol;}catch(e){}
  }
}

// ========== NAVIGATION & ROUTING ==========
// Globale Sektion-Variable für Navigation
let currentSection='home';
function openBackend(){document.getElementById('backend-page').classList.add('open');if(loggedIn)showAdminUI();}
function closeBackend(){document.getElementById('backend-page').classList.remove('open');history.replaceState({},'',window.location.pathname);}
window.addEventListener('hashchange',()=>{
  if(window.location.hash==='#backend'){
    history.replaceState({},'',window.location.pathname);
    openBackend();
  }
});

// ========== NAVIGATION MENUS ==========
// Baut die Hauptnavigation aus Sektionen
function buildNav(){
  const links=(data.sections||[]).map(s=>
    `<a onclick="navigate('${s.id}')" data-view="${s.id}">${escH(L(s.label))}</a>`
  ).join('');
  document.getElementById('main-nav').innerHTML=links;
  document.getElementById('mobile-nav').innerHTML=links;
}

// ========== MOBILE NAVIGATION DRAWER ==========
// Toggle mobile Navigationsmenu
function toggleMobileNav(){
  const open=document.getElementById('mobile-nav-drawer').classList.toggle('open');
  document.getElementById('mobile-nav-overlay').classList.toggle('open',open);
  document.getElementById('burger-btn').classList.toggle('open',open);
}
function closeMobileNav(){
  document.getElementById('mobile-nav-drawer').classList.remove('open');
  document.getElementById('mobile-nav-overlay').classList.remove('open');
  document.getElementById('burger-btn').classList.remove('open');
}

function navigate(sectionId,projectIdx){
  stopAllMedia();
  closeMobileNav();
  // Header transparency: remove for all, add for home
  document.querySelector('header').classList.remove('transparent');
  // Hide all backgrounds
  ['section-bg','project-bg','section-bg-overlay','home-bg','termine-bg','bio-bg','kontakt-bg'].forEach(id=>{
    const el=document.getElementById(id);if(el)el.style.display='none';
  });
  document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));
  document.querySelectorAll('nav a').forEach(a=>a.classList.remove('active'));
  if(sectionId==='home'){
    document.getElementById('view-home').classList.add('active');
    document.querySelector('header').classList.add('transparent');
    renderHomeText();renderHomeBg();renderCircles();currentSection='home';updateBgState();return;
  }
  const sec=(data.sections||[]).find(s=>s.id===sectionId);if(!sec)return;
  document.querySelectorAll(`nav a[data-view="${sectionId}"]`).forEach(el=>el.classList.add('active'));
  if(projectIdx!==undefined){
    const vp=document.getElementById('view-project');
    vp.classList.add('active');
    vp._sectionId=sectionId;vp._projectIdx=projectIdx;
    renderProject(sectionId,projectIdx);currentSection='project';
    document.getElementById('back-btn').onclick=()=>navigate(sectionId);
    document.getElementById('back-btn').textContent=t('back');
    applyProjectBg(sectionId,projectIdx);
    updateBgState();return;
  }
  currentSection=sectionId;
  if(sec.type==='projects'){document.getElementById('view-section').classList.add('active');renderSectionList(sectionId);}
  else if(sec.type==='termine'){document.getElementById('view-termine').classList.add('active');renderTermineView();}
  else if(sec.type==='bio'){document.getElementById('view-bio').classList.add('active');renderBio();applyPageBg('bio');}
  else if(sec.type==='kontakt'){document.getElementById('view-kontakt').classList.add('active');renderKontakt();applyPageBg('kontakt');}
  updateBgState();
}

function applyPageBg(page){
  const bgData=page==='bio'?data.bioBg:data.kontaktBg;
  const bgEl=document.getElementById(page+'-bg');
  if(!bgEl||!bgData||!bgData.active||!bgData.url){if(bgEl)bgEl.style.display='none';return;}
  bgEl.style.backgroundImage="url('"+escH(bgData.url)+"')";
  bgEl.style.backgroundSize='cover';
  bgEl.style.backgroundPosition='50% 50%';
  bgEl.style.opacity=bgData.opacity||1;
  bgEl.style.display='block';
}

function renderTermineView(){
  const sb=(data.sectionBg||{}).termine||{};
  const tbg=document.getElementById('termine-bg');
  if(tbg&&sb.active&&sb.url){
    tbg.style.backgroundImage="url('"+escH(sb.url)+"')";
    tbg.style.backgroundSize='cover';
    tbg.style.backgroundPosition=(sb.posX||'50')+'% '+(sb.posY||'50')+'%';
    tbg.style.opacity=sb.opacity||1;
    tbg.style.display='block';
  }else if(tbg){tbg.style.display='none';}
  const events=data.events||[];
  const upcoming=events.filter(e=>!isEventPast(e)).sort((a,b)=>new Date(a.date)-new Date(b.date));
  const past=events.filter(e=>isEventPast(e)).sort((a,b)=>new Date(b.date)-new Date(a.date));
  let html='';
  if(upcoming.length){
    html+='<div class="events-section">';
    upcoming.forEach(ev=>{
      html+=`<div class="event-item"><span class="event-date">${formatDate(ev.date)}</span><span class="event-title">${ev.link?`<a href="${escH(ev.link)}" target="_blank">${escH(L(ev.title))}</a>`:escH(L(ev.title))}</span></div>`;
    });
    html+='</div>';
  }
  if(upcoming.length&&past.length){
    html+='<div class="events-divider"></div>';
  }
  if(past.length){
    html+='<div class="events-section">';
    past.forEach(ev=>{
      html+=`<div class="event-item event-past"><span class="event-date">${formatDate(ev.date)}</span><span class="event-title">${ev.link?`<a href="${escH(ev.link)}" target="_blank">${escH(L(ev.title))}</a>`:escH(L(ev.title))}</span></div>`;
    });
    html+='</div>';
  }
  if(!upcoming.length&&!past.length)html='<p style="color:#888;font-size:.85rem;">Keine Termine.</p>';
  document.getElementById('termine-content').innerHTML=html;
}

function applyProjectBg(sectionId,projectIdx){
  const pbg=document.getElementById('project-bg');if(!pbg)return;
  const overlay=document.getElementById('section-bg-overlay');

  // Projekt-eigenes Bild hat Vorrang, sonst Rubrik-Bild
  const project=(data.projects[sectionId]||[])[projectIdx]||{};
  const sb=(data.sectionBg||{})[sectionId]||{};
  const projectBgUrl=project.bgImg||'';
  const sectionBgUrl=sb.url||'';
  const url=projectBgUrl||(sb.active?sectionBgUrl:'');

  if(!url){pbg.style.display='none';if(overlay)overlay.style.display='none';return;}

  pbg.style.backgroundImage="url('"+escH(url)+"')";
  pbg.style.backgroundSize='cover';
  pbg.style.backgroundRepeat='no-repeat';
  pbg.style.backgroundPosition=(sb.posX||'50')+'% '+(sb.posY||'50')+'%';
  pbg.style.opacity=sb.opacity||1;
  pbg.style.display='block';

  // Overlay gradient
  if(!overlay){
    const ov=document.createElement('div');
    ov.id='section-bg-overlay';
    ov.style.cssText='position:fixed;inset:0;z-index:0;pointer-events:none;';
    document.body.appendChild(ov);
  }
  const ov2=document.getElementById('section-bg-overlay');
  ov2.style.background='none';
  ov2.style.display='block';
}

function renderAll(){
  currentSection = currentSection || 'home';
  document.querySelector('header').classList.toggle('transparent', currentSection === 'home');
  document.getElementById('header-name').textContent=data.name||'';
  document.getElementById('header-sub').textContent=L(data.sub)||'';
  document.getElementById('site-title-tag').textContent=data.name||'';
  document.getElementById('footer-text').textContent=data.footer||'© 2026';
  buildNav();renderHomeText();renderHomeBg();renderCircles();applyLangUI();
  if(currentSection&&currentSection!=='home'&&currentSection!=='project'){
    const sec=(data.sections||[]).find(s=>s.id===currentSection);
    if(sec){
      if(sec.type==='projects')renderSectionList(currentSection);
      else if(sec.type==='bio')renderBio();
      else if(sec.type==='kontakt')renderKontakt();
    }
  }
}

// HOME
function renderHomeText(){
  const el=document.getElementById('home-text');
  if(!el)return;
  const text=L(data.homeText)||'';
  el.innerHTML=escH(text).replace(/\n/g,'<br>');
}

function renderHomeBg(){
  const bg=document.getElementById('home-bg');
  if(!bg)return;
  const hb=data.homeBg||{};
  const url=hb.url||(data.eventsImage||{}).url||'';
  const active=hb.active!==undefined?hb.active:((data.eventsImage||{}).active||false);
  if(active&&url){
    bg.style.backgroundImage="url('"+escH(url)+"')";
    bg.style.backgroundPosition=(hb.posX||'50')+'% '+(hb.posY||'50')+'%';
    bg.style.opacity=hb.opacity||1;
    bg.style.display='block';
  }else{bg.style.display='none';}
}
function isEventPast(ev){
  if(!ev||!ev.date)return false;
  const endOfDay=new Date(ev.date+'T23:59:59');
  return !isNaN(endOfDay) && endOfDay.getTime() < Date.now();
}
function isUpcoming(ev){return !isEventPast(ev);}
function formatDate(d){if(!d)return'';try{return new Date(d+'T12:00:00').toLocaleDateString(lang==='en'?'en-GB':'de-DE',{day:'2-digit',month:'2-digit',year:'numeric'});}catch(e){return d;}}
function renderHomeEvents(){
  const bg=document.getElementById('home-bg');
  if(bg){
    const hb=data.homeBg||{};
    // fallback to eventsImage for legacy data
    const url=hb.url||(data.eventsImage||{}).url||'';
    const active=hb.active!==undefined?hb.active:((data.eventsImage||{}).active||false);
    if(active&&url){
      bg.style.backgroundImage="url('"+escH(url)+"')";
      bg.style.backgroundPosition=(hb.posX||'50')+'% '+(hb.posY||'50')+'%';
      bg.style.opacity=hb.opacity||1;
      bg.style.display='block';
    }else{bg.style.display='none';}
  }
  const el=document.getElementById('home-events');
  const events=data.events||[];if(!events.length){el.innerHTML='';return;}
  const upcoming=events.filter(e=>!isEventPast(e)).sort((a,b)=>new Date(b.date)-new Date(a.date));
  const past=events.filter(e=>isEventPast(e)).sort((a,b)=>new Date(b.date)-new Date(a.date));
  let html='';
  if(upcoming.length){html+=`<div class="events-section"><div class="events-heading">${t('upcoming')}</div>`;upcoming.forEach(ev=>{html+=`<div class="event-item"><span class="event-date">${formatDate(ev.date)}</span><span class="event-title">${ev.link?`<a href="${escH(ev.link)}" target="_blank">${escH(L(ev.title))}</a>`:escH(L(ev.title))}</span></div>`;});html+='</div>';}
  if(past.length){html+=`<div class="events-section"><div class="events-heading">${t('past')}</div>`;past.forEach(ev=>{html+=`<div class="event-item event-past"><span class="event-date">${formatDate(ev.date)}</span><span class="event-title">${ev.link?`<a href="${escH(ev.link)}" target="_blank">${escH(L(ev.title))}</a>`:escH(L(ev.title))}</span></div>`;});html+='</div>';}
  el.innerHTML=html;
}

// PROJEKTLISTE
function renderSectionList(sectionId){
  const bg=document.getElementById('section-bg');
  if(bg){
    const sb=(data.sectionBg||{})[sectionId]||{};
    if(sb.active&&sb.url){
      bg.style.backgroundImage="url('"+escH(sb.url)+"')";
      bg.style.backgroundPosition=(sb.posX||'50')+'% '+(sb.posY||'50')+'%';
      bg.style.opacity=sb.opacity||1;
      bg.style.display='block';
      let overlay=document.getElementById('section-bg-overlay');
      if(!overlay){overlay=document.createElement('div');overlay.id='section-bg-overlay';overlay.style.cssText='position:fixed;inset:0;z-index:0;pointer-events:none;';document.body.appendChild(overlay);}
      overlay.style.background='none';overlay.style.display='block';
    }else{
      bg.style.display='none';
      const overlay=document.getElementById('section-bg-overlay');
      if(overlay)overlay.style.display='none';
    }
  }
  const ul=document.getElementById('section-list');
  const projects=data.projects[sectionId]||[];
  if(!projects.length){ul.innerHTML=`<li style="padding:1rem 0;color:#888;font-size:.85rem;">${t('noProjects')}</li>`;return;}
  ul.innerHTML=projects.map((p,i)=>`
    <li class="project-item" onclick="navigate('${sectionId}',${i})">
      <div class="project-item-header">
        <span class="project-title">${escH(L(p.title))||'—'}</span>
        <span class="project-year">${escH(p.year||'')}</span>
      </div>
      ${L(p.shortDesc)?`<div class="project-short-desc">${escH(L(p.shortDesc))}</div>`:''}
    </li>`).join('');
  // Rechte Spalte mit Rubrik-Medien befüllen
  const mediaCol=document.getElementById('section-media-col');
  if(!mediaCol)return;
  const sMedia=(data.sectionMedia||{})[sectionId]||[];
  if(!sMedia.length){mediaCol.innerHTML='';return;}
  const photos=sMedia.filter(m=>m.type==='photo');
  let html='';
  if(photos.length){html+='<div class="photo-grid-view" style="margin-bottom:1.5rem;">';photos.forEach(m=>{html+=`<img src="${escH(m.url)}" alt="" onclick="openLB('${escH(m.url)}')" loading="lazy" onerror="this.style.display='none'" style="aspect-ratio:4/3;object-fit:cover;"/>`;});html+='</div>';}
  sMedia.filter(m=>m.type!=='photo').forEach(m=>{html+=`<div class="media-block">${buildEmbed(m)}`;if(m.caption&&m.type!=='link'&&m.type!=='instagram')html+=`<div class="media-caption">${escH(m.caption)}</div>`;html+='</div>';});
  mediaCol.innerHTML=html;
}

// EINZELNES PROJEKT
function renderProject(sectionId,idx){
  const p=(data.projects[sectionId]||[])[idx];if(!p)return;
  let html=`<h1 class="project-heading">${escH(L(p.title))}</h1>`;
  const tags=L(p.tags);
  if(p.year||tags)html+=`<div class="project-meta">${[p.year,tags].filter(Boolean).map(escH).join(' · ')}</div>`;
  const desc=L(p.desc);
  if(desc)html+=`<p class="project-desc">${escH(desc).replace(/\n/g,'<br>')}</p>`;
  const photos=(p.media||[]).filter(m=>m.type==='photo');
  if(photos.length){html+='<div class="photo-grid-view">';photos.forEach(m=>{html+=`<img src="${escH(m.url)}" alt="${escH(m.caption||'')}" onclick="openLB('${escH(m.url)}')" loading="lazy" onerror="this.style.display='none'"/>`;});html+='</div>';}
  (p.media||[]).filter(m=>m.type!=='photo').forEach(m=>{
    html+=`<div class="media-block">${buildEmbed(m)}`;
    if(m.caption&&m.type!=='link'&&m.type!=='instagram')html+=`<div class="media-caption">${escH(m.caption)}</div>`;
    html+='</div>';
  });
  document.getElementById('project-content').innerHTML=html;
}

function buildEmbed(m){
  if(m.type==='youtube'){const id=extractYT(m.url);return id?`<div class="embed-wrap"><iframe src="https://www.youtube.com/embed/${id}" allowfullscreen allow="accelerometer;autoplay;clipboard-write;encrypted-media;gyroscope;picture-in-picture"></iframe></div>`:'<p style="color:#888;font-size:.8rem;">Ungültige YouTube-URL</p>';}
  if(m.type==='vimeo'){const id=extractVimeo(m.url);return id?`<div class="embed-wrap"><iframe src="https://player.vimeo.com/video/${id}" allowfullscreen allow="autoplay;fullscreen;picture-in-picture"></iframe></div>`:'<p style="color:#888;font-size:.8rem;">Ungültige Vimeo-URL</p>';}
  if(m.type==='soundcloud'){const srcMatch=m.url.match(/src=["']([^"']+)["']/);if(srcMatch){return`<div class="embed-audio"><iframe height="166" scrolling="no" frameborder="no" allow="autoplay" style="width:100%" src="${escH(srcMatch[1])}"></iframe></div>`;}return`<div class="embed-audio"><iframe height="166" scrolling="no" frameborder="no" allow="autoplay" style="width:100%" src="https://w.soundcloud.com/player/?url=${encodeURIComponent(m.url)}&color=%231a1a1a&auto_play=false&hide_related=true&show_comments=false&show_user=true&show_reposts=false"></iframe></div>`;}
  if(m.type==='bandcamp'){
    // Unterstützt sowohl die src-URL direkt als auch den kopierten iframe-Code
    let src=m.url;
    const match=m.url.match(/src=["']([^"']+)["']/);
    if(match)src=match[1];
    return`<div class="embed-audio"><iframe style="width:100%;height:120px;border:0;" src="${escH(src)}" seamless></iframe></div>`;
  }
  if(m.type==='instagram'||m.type==='link')return`<a class="ext-link" href="${escH(m.url)}" target="_blank" rel="noopener">${escH(m.caption||m.url)}</a>`;
  return'';
}
function extractYT(url){const m=url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([a-zA-Z0-9_-]{11})/);return m?m[1]:null;}
function extractVimeo(url){const m=url.match(/vimeo\.com\/(\d+)/);return m?m[1]:null;}

// BIO / KONTAKT
function renderBio(){
  const img=document.getElementById('bio-img-el'),ph=document.getElementById('bio-img-placeholder');
  if(data.bio&&data.bio.img){img.src=data.bio.img;img.style.display='block';ph.style.display='none';}
  else{img.style.display='none';ph.style.display='flex';ph.textContent=t('foto');}
  document.getElementById('bio-text-el').innerHTML=escH(L((data.bio||{}).text)||'').replace(/\n/g,'<br>');
}
function renderKontakt(){
  const list=document.getElementById('contact-links-list');
  const links=data.contactLinks||[];
  if(!links.length){list.innerHTML='';return;}
  list.innerHTML=links.map(l=>`<div class="contact-link-item"><span class="contact-link-label">${escH(l.label)}</span><span class="contact-link-val"><a href="${l.url.startsWith('http')||l.url.startsWith('mailto:')?escH(l.url):'https://'+escH(l.url)}" target="_blank">${escH(l.url)}</a></span></div>`).join('');
}
function applyLangUI(){
  const s=(id,k)=>{const e=document.getElementById(id);if(e)e.textContent=t(k);};
  s('cf-title','cfTitle');s('cf-label-name','cfName');s('cf-label-email','cfEmail');
  s('cf-label-subject','cfSubject');s('cf-label-msg','cfMsg');s('cf-send-btn','cfSend');
}
async function sendMail(){
  const email=document.getElementById('cf-email').value.trim();
  const msg=document.getElementById('cf-msg').value.trim();
  const name=document.getElementById('cf-name').value.trim();
  const subject=document.getElementById('cf-subject').value.trim();
  const status=document.getElementById('form-status');
  const btn=document.getElementById('cf-send-btn');
  if(!email||!msg){status.textContent=t('cfFill');return;}
  btn.disabled=true;
  status.style.color='var(--muted)';
  status.textContent=lang==='en'?'Sending…':'Wird gesendet…';
  try{
    const res=await fetch('https://formspree.io/f/xrerydal',{
      method:'POST',
      headers:{'Content-Type':'application/json','Accept':'application/json'},
      body:JSON.stringify({name,email,subject,message:msg})
    });
    if(res.ok){
      status.style.color='green';
      status.textContent=lang==='en'?'Message sent — thank you!':'Nachricht gesendet — danke!';
      document.getElementById('cf-name').value='';
      document.getElementById('cf-email').value='';
      document.getElementById('cf-subject').value='';
      document.getElementById('cf-msg').value='';
    }else{
      status.style.color='#c00';
      status.textContent=lang==='en'?'Something went wrong. Please try again.':'Etwas ist schiefgelaufen. Bitte nochmal versuchen.';
    }
  }catch(e){
    status.style.color='#c00';
    status.textContent=lang==='en'?'No connection. Please try again.':'Keine Verbindung. Bitte nochmal versuchen.';
  }
  btn.disabled=false;
}

