// EXPORT & GITHUB DEPLOY
const GITHUB_USER='floschirmer';
const GITHUB_REPO='portfolio';
const GITHUB_FILE='script.js';
const GITHUB_BRANCH='main';

function getGithubToken(){return localStorage.getItem('pf_gh_token')||'';}

async function exportSite(){
  // Alle offenen Felder automatisch speichern
  try{if(document.getElementById('a-name'))saveGeneral();}catch(e){}
  try{if(document.getElementById('a-bio-img'))saveBio();}catch(e){}

  const token=getGithubToken();
  const btn=document.querySelector('.export-btn');

  // Holt saubere Kopie von script.js vom Server und ersetzt nur _DATA_
  async function buildNewHtml(){
    let originalHtml;
    try{
      const resp=await fetch('script.js',{cache:'no-store'});
      if(resp.ok)originalHtml=await resp.text();
    }catch(e){}
    // Fallback: aktuellen script-Inhalt aus DOM lesen
    if(!originalHtml){
      const sc=Array.from(document.scripts).find(s=>s.src&&s.src.includes('script.js'));
      if(sc){try{const r=await fetch(sc.src,{cache:'no-store'});if(r.ok)originalHtml=await r.text();}catch(e){}}
    }
    if(!originalHtml)throw new Error('script.js konnte nicht geladen werden. Bitte Seite neu laden.');
    const dataJson=JSON.stringify(data);
    const marker='var _DATA_ = ';
    const markerEnd=';\nvar data = JSON.parse';
    const start=originalHtml.indexOf(marker);
    const end=originalHtml.indexOf(markerEnd);
    if(start===-1||end===-1)throw new Error('Daten-Marker nicht gefunden. Bitte Seite neu laden.');
    return originalHtml.substring(0,start)+marker+dataJson+originalHtml.substring(end);
  }

  if(!token){
    alert('Kein GitHub-Token gespeichert. Bitte Token eintragen und speichern.');
    return;
  }

  // Mit Token → direkt zu GitHub pushen
  if(btn){btn.textContent='⏳ Wird veröffentlicht…';btn.disabled=true;}
  try{
    const newHtml=await buildNewHtml();
    const b64=btoa(unescape(encodeURIComponent(newHtml)));

    // Aktuellen SHA holen (nötig für GitHub API Update)
    const apiBase=`https://api.github.com/repos/${GITHUB_USER}/${GITHUB_REPO}/contents/${GITHUB_FILE}`;
    const headers={'Authorization':'token '+token,'Content-Type':'application/json','Accept':'application/vnd.github.v3+json'};
    const shaRes=await fetch(apiBase+'?ref='+GITHUB_BRANCH,{headers});
    if(!shaRes.ok){
      const err=await shaRes.json();
      throw new Error('GitHub Fehler: '+(err.message||shaRes.status));
    }
    const shaData=await shaRes.json();
    const sha=shaData.sha;

    // Datei pushen
    const pushRes=await fetch(apiBase,{
      method:'PUT',
      headers,
      body:JSON.stringify({
        message:'Update index.html via Backend',
        content:b64,
        sha,
        branch:GITHUB_BRANCH
      })
    });
    if(!pushRes.ok){
      const err=await pushRes.json();
      throw new Error('Push Fehler: '+(err.message||pushRes.status));
    }
    if(btn){btn.textContent='✓ Live veröffentlicht!';setTimeout(()=>{btn.textContent='🚀 Speichern & veröffentlichen';btn.disabled=false;},3000);}
    showSaveNotice();
  }catch(err){
    alert('Fehler beim Veröffentlichen: '+err.message+'\n\nBitte prüfe deinen GitHub-Token im Backend unter „Allgemein".');
    if(btn){btn.textContent='🚀 Speichern & veröffentlichen';btn.disabled=false;}
  }
}
function showSaveNotice(){
  try{localStorage.setItem('pf_data',JSON.stringify(data));}catch(e){}
  const n=document.getElementById('save-notice');n.classList.add('show');setTimeout(()=>n.classList.remove('show'),2000);
}
function saveGhToken(){
  const val=document.getElementById('gh-token-input').value.trim();
  if(!val){alert('Bitte Token eingeben.');return;}
  localStorage.setItem('pf_gh_token',val);
  document.getElementById('gh-token-input').value='';
  updateTokenStatus();
}
async function updateTokenStatus(){
  const el=document.getElementById('gh-token-status');if(!el)return;
  const stored=localStorage.getItem('pf_gh_token');
  const inputVal=document.getElementById('gh-token-input')?.value.trim();
  if(inputVal){el.style.color='#888';el.textContent='Noch nicht gespeichert — klicke „Token speichern“.';return;}
  if(!stored){el.style.color='#c00';el.textContent='Kein Token — Veröffentlichen nicht möglich.';return;}
  el.style.color='#888';el.textContent='⧗ Prüfe Token…';
  try{
    const res=await fetch('https://api.github.com/user',{headers:{'Authorization':'token '+stored,'Accept':'application/vnd.github.v3+json'}});
    if(res.ok){
      const u=await res.json();
      el.style.color='green';el.textContent='✓ Token gültig ('+u.login+'). Veröffentlichen möglich.';
    }else if(res.status===401){
      el.style.color='#c00';el.textContent='✗ Token ungültig oder abgelaufen — bitte neuen Token eintragen.';
    }else{
      el.style.color='#c00';el.textContent='✗ GitHub antwortet nicht (Status '+res.status+').';
    }
  }catch(e){
    el.style.color='#888';el.textContent='⚠ Keine Verbindung zu GitHub — Token-Status unbekannt.';
  }
}

// Shared SVG defs injected once into DOM — avoids repeating gradients per CD
