// SOUND CIRCLES / CD ICONS
function renderCircles(){
  const container=document.getElementById('circles-container');
  if(!container)return;
  injectCdDefs();
  const circles=data.soundCircles||[];
  const isMobile=window.innerWidth<=700;
  const scaleFactor=isMobile?Math.min(window.innerWidth/480,0.65):1;
  container.innerHTML='';
  circles.forEach((c,i)=>{
    const baseSize=c.size||100;
    const size=Math.round(baseSize*scaleFactor);
    const expandedSize=Math.max(isMobile?Math.min(window.innerWidth*0.88,260):280,size*2.6);
    const div=document.createElement('div');
    div.className='sound-circle';
    div.dataset.baseSize=size;
    div.dataset.expandedSize=expandedSize;
    div.dataset.idx=i;
    div.style.cssText=`left:${c.x}%;top:${c.y}%;width:${size}px;height:${size}px;margin-left:-${size/2}px;margin-top:-${size/2}px;animation-delay:${-(i*2.1)}s;`;
    div.innerHTML=`<div class="cd-svg-wrap">${cdSVG()}</div>
      <div class="cd-inner-player"><div id="cdp-${i}"></div></div>
      <button class="cd-close" onclick="collapseCd(event,this.parentElement)">✕</button>`;

    const dragState={dragging:false,preventClick:false,startX:0,startY:0,startXpct:0,startYpct:0};
    function startDrag(clientX,clientY){
      dragState.dragging=true;
      dragState.preventClick=false;
      dragState.startX=clientX;
      dragState.startY=clientY;
      dragState.startXpct=c.x;
      dragState.startYpct=c.y;
      div.style.cursor='grabbing';
    }
    function updateDrag(clientX,clientY){
      if(!dragState.dragging) return;
      let rect=container.getBoundingClientRect();
      if(!rect.width||!rect.height){
        const alt=container.parentElement?.getBoundingClientRect();
        if(alt&&alt.width&&alt.height) rect=alt;
      }
      if(!rect.width||!rect.height) return;
      const dx=(clientX-dragState.startX)/rect.width*100;
      const dy=(clientY-dragState.startY)/rect.height*100;
      const nx=Math.max(5,Math.min(95,dragState.startXpct+dx));
      const ny=Math.max(5,Math.min(95,dragState.startYpct+dy));
      if(Math.abs(dx)>1||Math.abs(dy)>1){
        dragState.preventClick=true;
        c.x=Math.round(nx*10)/10;
        c.y=Math.round(ny*10)/10;
        div.style.left=c.x+'%';
        div.style.top=c.y+'%';
      }
    }
    function endDrag(){
      if(!dragState.dragging) return;
      dragState.dragging=false;
      div.style.cursor='grab';
    }
    div.addEventListener('pointerdown',function(e){
      if(e.button!==0) return;
      e.preventDefault();
      div.setPointerCapture?.(e.pointerId);
      startDrag(e.clientX,e.clientY);
    });
    div.addEventListener('pointermove',function(e){
      updateDrag(e.clientX,e.clientY);
      if(dragState.dragging) e.preventDefault();
    });
    div.addEventListener('pointerup',function(e){
      if(!dragState.dragging) return;
      div.releasePointerCapture?.(e.pointerId);
      endDrag();
      if(dragState.preventClick){
        e.stopPropagation();
        e.preventDefault();
      }
    });
    div.addEventListener('pointercancel',function(){endDrag();});
    div.addEventListener('mousedown',function(e){
      if(e.button!==0) return;
      startDrag(e.clientX,e.clientY);
    });
    div.addEventListener('mousemove',function(e){
      updateDrag(e.clientX,e.clientY);
      if(dragState.dragging) e.preventDefault();
    });
    div.addEventListener('mouseup',function(){endDrag();});
    div.addEventListener('touchstart',function(e){
      if(e.touches.length!==1) return;
      const t=e.touches[0];
      startDrag(t.clientX,t.clientY);
      e.preventDefault();
    },{passive:false});
    div.addEventListener('touchmove',function(e){
      if(!dragState.dragging||e.touches.length!==1) return;
      updateDrag(e.touches[0].clientX,e.touches[0].clientY);
      e.preventDefault();
    },{passive:false});
    div.addEventListener('touchend',function(e){
      if(!dragState.dragging)return;
      const wasDrag=dragState.preventClick;
      endDrag();
      // touchstart.preventDefault() suppresses the synthetic click on iOS — handle tap manually
      if(!wasDrag){
        if(e.target.closest('.cd-close')){_collapseCdEl(div);return;}
        if(div.classList.contains('expanded')){_collapseCdEl(div);}else{expandCd(div,c,i);}
      }
    });
    div.addEventListener('click',function(e){
      if(dragState.preventClick){
        dragState.preventClick=false;
        return;
      }
      if(e.target.closest('.cd-close'))return;
      if(this.classList.contains('expanded')){
        _collapseCdEl(this);
      }else{
        expandCd(this,c,i);
      }
    });

    container.appendChild(div);
  });
}

function stopSplashAudio(){
  if(splashAudio&&splashAudio.tagName==='AUDIO'){
    splashAudio.pause();
  }else{
    const iframe=document.getElementById('splash-audio-frame');
    if(iframe)try{iframe.contentWindow.postMessage(JSON.stringify({method:'pause'}),'*');}catch(e){}
  }
}

function expandCd(el,c,idx){
  stopAllMedia();
  document.querySelectorAll('.sound-circle.expanded').forEach(other=>{
    if(other!==el)_collapseCdEl(other);
  });
  const baseSize=parseInt(el.dataset.baseSize)||100;
  const expandedSize=parseInt(el.dataset.expandedSize)||280;
  const scale=expandedSize/baseSize;
  el.classList.add('expanded');
  el.style.transform=`scale(${scale})`;
  const inner=document.getElementById('cdp-'+idx);
  if(inner){
    inner.innerHTML=buildCircleEmbedExpanded(c,expandedSize);
    const iframe=inner.querySelector('iframe');
    if(iframe){
      iframe.addEventListener('load',()=>playEmbedIframe(iframe));
      playEmbedIframe(iframe);
    }
  }
}

function playEmbedIframe(iframe){
  if(!iframe||!iframe.contentWindow) return;
  const src=(iframe.src||'').toLowerCase();
  try{
    if(src.includes('w.soundcloud.com/player')||src.includes('soundcloud.com')){
      iframe.contentWindow.postMessage(JSON.stringify({method:'play'}),'*');
    } else if(src.includes('bandcamp.com')){
      // Bandcamp startet nicht automatisch, Play-Button bleibt sichtbar
      return;
    } else if(src.includes('youtube.com/embed')){
      iframe.contentWindow.postMessage(JSON.stringify({event:'command',func:'playVideo',args:''}),'*');
    } else if(src.includes('player.vimeo.com')){
      iframe.contentWindow.postMessage(JSON.stringify({method:'play'}),'*');
    }
  }catch(e){}
}

function buildCircleEmbedExpanded(c,size){
  const h=Math.round(size*0.26);
  if(!c.url)return'';
  if(c.source==='soundcloud'){
    const src=c.url.includes('w.soundcloud.com')?c.url:
      'https://w.soundcloud.com/player/?url='+encodeURIComponent(c.url)+'&color=%231a1a1a&auto_play=true&hide_related=true&show_comments=false&show_user=false&show_reposts=false&show_teaser=false';
    return`<iframe src="${escH(src)}" height="${h}" scrolling="no" frameborder="no" allow="autoplay" style="width:82%;border-radius:8px;border:none;display:block;margin:0 auto;box-shadow:0 2px 12px rgba(0,0,0,0.15);"></iframe>`;
  }
  if(c.source==='bandcamp'){
    let src=c.url;const m=c.url.match(/src=["']([^"']+)["']/);if(m)src=m[1];
    src=src.replace(/\/?$/,'');
    // Entferne autoplay, damit Play-Button sichtbar bleibt
    src=src.replace(/([&?])autoplay=\d*/,'$1').replace(/\?$/, '');
    return`<iframe src="${escH(src)}" allow="autoplay; fullscreen; encrypted-media" allowfullscreen style="width:82%;height:${h}px;border:0;border-radius:8px;display:block;margin:0 auto;box-shadow:0 2px 12px rgba(0,0,0,0.15);" seamless></iframe>`;
  }
  return'';
}

function collapseCd(e,el){e.stopPropagation();_collapseCdEl(el);}
function _collapseCdEl(el){
  const idx=el.dataset.idx;
  el.classList.remove('expanded');
  el.style.transform='scale(1)';
  // Stop audio immediately by destroying iframe
  if(idx!==undefined){
    const inner=document.getElementById('cdp-'+idx);
    if(inner)inner.innerHTML='';
  }
}


// ADMIN TABS UPDATE
function buildAdminTabs(){
  const tabsEl=document.getElementById('admin-tabs');
  const panelsEl=document.getElementById('admin-tab-panels');
  const projSecs=(data.sections||[]).filter(s=>s.type==='projects');
  const allTabs=[
    {id:'general',label:'Allgemein'},
    {id:'splash',label:'Splash / Sound'},
    {id:'circles',label:'Startseiten-Kreise'},
    {id:'termine',label:'Termine'},
    ...projSecs.map(s=>({id:'proj_'+s.id,label:L(s.label)})),
    {id:'bio',label:'Bio'},
    {id:'kontakt',label:'Kontakt'}
  ];
  tabsEl.innerHTML=allTabs.map((t,i)=>`<div class="tab${i===0?' active':''}" onclick="switchTab('${t.id}',this)">${escH(t.label)}</div>`).join('');
  panelsEl.innerHTML=allTabs.map((t,i)=>`<div class="tab-panel${i===0?' active':''}" id="tab-${t.id}"></div>`).join('');
  renderTabGeneral();renderTabSplash();renderTabCircles();renderTabTermine();
  projSecs.forEach(s=>renderTabProjects(s.id));renderTabBio();renderTabKontakt();
}

// Single shared drag state + listeners — defined BEFORE renderCdCanvas uses them
let _cdDrag=null;
function _cdMouseMove(e){
  if(!_cdDrag)return;
  const {dot,c,canvas}=_cdDrag;
  const rect=canvas.getBoundingClientRect();
  // Position relativ zum Canvas-Rect berechnen (scroll-unabhängig)
  let nx=((e.clientX-rect.left)/rect.width*100);
  let ny=((e.clientY-rect.top)/rect.height*100);
  nx=Math.max(3,Math.min(97,nx));ny=Math.max(3,Math.min(97,ny));
  c.x=Math.round(nx*10)/10;c.y=Math.round(ny*10)/10;
  dot.style.left=(c.x/100)*rect.width+'px';
  dot.style.top=(c.y/100)*rect.height+'px';
}
function _cdMouseUp(){
  if(!_cdDrag)return;
  _cdDrag.dot.style.cursor='grab';_cdDrag=null;
  renderCircles();showSaveNotice();
}
function _cdTouchMove(e){
  if(!_cdDrag)return;
  const {dot,c,canvas}=_cdDrag;
  const rect=canvas.getBoundingClientRect();
  let nx=((e.touches[0].clientX-rect.left)/rect.width*100);
  let ny=((e.touches[0].clientY-rect.top)/rect.height*100);
  nx=Math.max(3,Math.min(97,nx));ny=Math.max(3,Math.min(97,ny));
  c.x=Math.round(nx*10)/10;c.y=Math.round(ny*10)/10;
  dot.style.left=(c.x/100)*rect.width+'px';
  dot.style.top=(c.y/100)*rect.height+'px';
  e.preventDefault();
}
function _cdTouchEnd(){_cdDrag=null;renderCircles();showSaveNotice();}
window.addEventListener('mousemove',_cdMouseMove);
window.addEventListener('mouseup',_cdMouseUp);

