function saveGeneral(){
  data.name=document.getElementById('a-name').value;
  data.sub={de:document.getElementById('a-sub-de').value,en:document.getElementById('a-sub-en').value};
  data.homeText={de:document.getElementById('a-home-de').value,en:document.getElementById('a-home-en').value};
  data.footer=document.getElementById('a-footer').value;
  renderAll();showSaveNotice();
}
function saveHomeBg(){
  if(!data.homeBg)data.homeBg={};
  data.homeBg.url=(document.getElementById('sb-url-home_page')?.value||'').trim();
  data.homeBg.active=document.getElementById('sb-active-home_page')?.value==='1';
  data.homeBg.posX=document.getElementById('sb-posx-home_page')?.value||'50';
  data.homeBg.posY=document.getElementById('sb-posy-home_page')?.value||'50';
  data.homeBg.opacity=(parseInt(document.getElementById('sb-opacity-home_page')?.value||100)/100);
  data.homeBg.glowStrength=parseInt(document.getElementById('sb-glow-home_page')?.value||70);
  if(currentSection==='home'){renderHomeText();renderHomeBg();renderCircles();updateBgState();}
  showSaveNotice();
}
async function changePw(){
  const p1=document.getElementById('a-pw1').value,p2=document.getElementById('a-pw2').value,msg=document.getElementById('pw-msg');
  if(!p1){msg.textContent='Bitte Passwort eingeben.';return;}
  if(p1!==p2){msg.textContent='Passwörter stimmen nicht überein.';return;}
  if(p1.length<6){msg.textContent='Mindestens 6 Zeichen.';return;}
  const h=await hashPw(p1);
  localStorage.setItem('pf_pw_hash',h);
  msg.style.color='green';msg.textContent='Gespeichert! Beim nächsten Export fest eingebaut.';
  setTimeout(()=>{msg.textContent='';msg.style.color='#888';},3000);
  document.getElementById('a-pw1').value='';document.getElementById('a-pw2').value='';
}

