function saveEvent(idx){
  data.events[idx].title={de:document.getElementById('ee-tde-'+idx).value,en:document.getElementById('ee-ten-'+idx).value};
  data.events[idx].date=document.getElementById('ee-date-'+idx).value;
  data.events[idx].link=document.getElementById('ee-link-'+idx).value.trim();
  data.events[idx].isPast=document.getElementById('ee-past-'+idx).value==='1';
  renderEventsAdmin();renderHomeEvents();showSaveNotice();
}
function addEvent(){
  const date=document.getElementById('ev-date').value,tde=document.getElementById('ev-tde').value.trim(),ten=document.getElementById('ev-ten').value.trim(),link=document.getElementById('ev-link').value.trim(),isPast=document.getElementById('ev-past').value==='1';
  if(!date||!tde){alert('Bitte Datum und Titel ausfüllen.');return;}
  if(!data.events)data.events=[];
  data.events.push({date,title:{de:tde,en:ten||tde},link:link||'',isPast});
  document.getElementById('ev-date').value='';document.getElementById('ev-tde').value='';document.getElementById('ev-ten').value='';document.getElementById('ev-link').value='';
  renderEventsAdmin();renderHomeEvents();showSaveNotice();
}
function deleteEvent(idx){if(!confirm('Löschen?'))return;data.events.splice(idx,1);renderEventsAdmin();renderHomeEvents();showSaveNotice();}
function saveEventsImage(){
  if(!data.eventsImage)data.eventsImage={};
  data.eventsImage.url=document.getElementById('ev-img-url').value.trim();
  data.eventsImage.active=document.getElementById('ev-img-active').value==='1';
  renderHomeEvents();showSaveNotice();
}

