// DRAG & DROP
let _dt=null,_di=null,_ds=null;
function dStart(e,type,idx,sectionId){_dt=type;_di=idx;_ds=sectionId||null;e.dataTransfer.effectAllowed='move';setTimeout(()=>e.target.classList.add('dragging'),0);}
function dOver(e,el){e.preventDefault();e.dataTransfer.dropEffect='move';el.classList.add('drag-over');}
function dLeave(el){el.classList.remove('drag-over');}
function dDrop(e,type,targetIdx,sectionId){
  e.preventDefault();const el=e.currentTarget;el.classList.remove('drag-over');
  if(_dt!==type||_di===targetIdx){cleanup();return;}
  if(type==='project'&&_ds===sectionId){const arr=data.projects[sectionId];const[item]=arr.splice(_di,1);arr.splice(targetIdx,0,item);renderProjectCards(sectionId);if(currentSection===sectionId)renderSectionList(sectionId);}
  cleanup();showSaveNotice();
}
function cleanup(){_dt=null;_di=null;_ds=null;document.querySelectorAll('.dragging').forEach(el=>el.classList.remove('dragging'));}

// SPLASH SCREEN & AUDIO
let splashAudio=null;
let isMuted=false;
let currentVolume=0.7;
let previousVolume=0.7;
let trackIndex=0;

function buildNativePlayer(tracks){
  const existing=document.getElementById('splash-audio-el');
  if(existing)existing.remove();
  if(!tracks||!tracks.length)return null;
  const audio=document.createElement('audio');
  audio.id='splash-audio-el';
  audio.style.display='none';
  audio.volume=currentVolume;
  audio.src=tracks[0].url;
  audio.addEventListener('ended',()=>{
    trackIndex=(trackIndex+1)%tracks.length;
    audio.src=tracks[trackIndex].url;
    audio.play().catch(()=>{});
  });
  document.body.appendChild(audio);
  return audio;
}

function buildSplashAudioPlayer(){
  stopAllMedia();
  const sa=data.splashAudio||{};
  if(!sa.active)return;
  if((sa.source||'tracks')==='tracks'){
    const tracks=(sa.tracks||[]).filter(t=>t.url);
    if(!tracks.length)return;
    trackIndex=0;
    splashAudio=buildNativePlayer(tracks);
    if(splashAudio){
      splashAudio.play().catch(()=>{});
      const vb=document.getElementById('volume-bar');
      if(vb)vb.style.display='flex';
    }
  }else{
    // SoundCloud or Bandcamp via iframe
    const url=sa.source==='soundcloud'?sa.soundcloudSrc:sa.bandcampSrc;
    if(!url)return;
    let iframe=document.getElementById('splash-audio-frame');
    if(iframe){
      // Reload src with auto_play=true — postMessage is not a user gesture on iOS and won't trigger playback
      let scUrl=url;
      if(sa.source==='soundcloud'){
        if(!scUrl.includes('w.soundcloud.com')){
          scUrl='https://w.soundcloud.com/player/?url='+encodeURIComponent(scUrl)+'&auto_play=true&hide_related=true&show_comments=false&show_user=true&show_reposts=false&show_teaser=false';
        }else{
          scUrl=scUrl.replace('auto_play=false','auto_play=true');
          if(!scUrl.includes('auto_play='))scUrl+='&auto_play=true';
        }
      }else{
        scUrl=url;scUrl+=scUrl.includes('?')?'&autoplay=1':'?autoplay=1';
      }
      iframe.src=scUrl;
    }else{
      // Create fresh with autoplay=true
      iframe=document.createElement('iframe');
      iframe.id='splash-audio-frame';
      iframe.style.cssText='display:none;position:absolute;width:0;height:0;';
      iframe.allow='autoplay';
      if(sa.source==='soundcloud'){
        let scUrl=url;
        if(!scUrl.includes('w.soundcloud.com')){
          scUrl='https://w.soundcloud.com/player/?url='+encodeURIComponent(url)+'&auto_play=true&hide_related=true&show_comments=false&show_user=true&show_reposts=false&show_teaser=false';
        }else{
          scUrl=scUrl.replace('auto_play=false','auto_play=true');
          if(!scUrl.includes('auto_play='))scUrl+='&auto_play=true';
        }
        iframe.src=scUrl;
      }else{
        let b=url;b+=b.includes('?')?'&autoplay=1':'?autoplay=1';iframe.src=b;
      }
      document.body.appendChild(iframe);
    }
    splashAudio=iframe;
    const vb=document.getElementById('volume-bar');
    if(vb)vb.style.display='flex';
  }
}

function toggleMute(){
  const slider=document.getElementById('volume-slider');
  const icon=document.getElementById('vol-icon');
  if(isMuted){
    const vol=previousVolume||0.7;
    currentVolume=vol;
    isMuted=false;
    slider.value=vol;
    icon.innerHTML='<path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>';
    applyVolume(vol);
  } else {
    previousVolume=currentVolume||previousVolume||0.7;
    isMuted=true;
    slider.value=0;
    icon.innerHTML='<path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>';
    applyVolume(0);
  }
}

function initSplash(){
  const splash=document.getElementById('splash');
  if(!splash)return;
  const sa=data.splashAudio||{};
  const splashImgUrl=data.splashImg||'';

  // Update CSS background (already set in CSS for initial load, update if changed in backend)
  if(splashImgUrl){
    splash.style.backgroundImage="url('"+splashImgUrl+"')";
    splash.style.backgroundSize='cover';
    splash.style.backgroundPosition='center';
  }

  // Hint text
  const hint=document.getElementById('splash-hint');
  if(hint)hint.textContent=lang==='en'?'click to enter':'klicken um einzutreten';

  // Skip splash if nothing configured
  if(!splashImgUrl&&!sa.active){splash.style.display='none';return;}

  // Preload SoundCloud iframe silently at page start so iOS allows playback on click
  if(sa.active&&sa.source==='soundcloud'&&sa.soundcloudSrc){
    if(!document.getElementById('splash-audio-frame')){
      const iframe=document.createElement('iframe');
      iframe.id='splash-audio-frame';
      iframe.style.cssText='display:none;position:absolute;width:0;height:0;';
      iframe.allow='autoplay';
      let scUrl=sa.soundcloudSrc;
      if(!scUrl.includes('w.soundcloud.com')){
        scUrl='https://w.soundcloud.com/player/?url='+encodeURIComponent(scUrl)+'&auto_play=false&hide_related=true&show_comments=false&show_user=true&show_reposts=false&show_teaser=false';
      }
      iframe.src=scUrl;
      document.body.appendChild(iframe);
      // Give iframe time to load, then on click we just trigger play via postMessage
      iframe.addEventListener('load',()=>{
        // Preloaded and ready — playback triggered by user click in buildSplashAudioPlayer
      });
    }
  }

  let clicked=false;
  splash.addEventListener('click',function(){
    if(!clicked){
      clicked=true;
      if(hint)hint.style.opacity='0';
      const ctaWrap=document.getElementById('splash-cta');
      const ctaText=document.getElementById('splash-cta-text');
      if(ctaWrap)ctaWrap.style.display='block';
      if(ctaText)setTimeout(()=>{ctaText.style.opacity='1';},50);
      if(sa.active){
        try{buildSplashAudioPlayer();}catch(err){console.warn('Splash audio konnte nicht gestartet werden:',err);}
      }
      // Show volume bar + start auto-hide on idle
      if(sa.active){
        const vb=document.getElementById('volume-bar');
        if(vb)vb.style.display='flex';
        initVolumeBarAutoHide();
      }
    }else{
      splash.classList.add('fade-out');
      setTimeout(()=>{splash.style.display='none';},1000);
    }
  });
}

// VOLUME BAR AUTO-HIDE: show on mouse move, hide after 7s idle
let _vbTimer=null;
function initVolumeBarAutoHide(){
  const vb=document.getElementById('volume-bar');
  if(!vb)return;
  function showVb(){
    vb.classList.remove('hidden');
    clearTimeout(_vbTimer);
    _vbTimer=setTimeout(()=>vb.classList.add('hidden'),7000);
  }
  document.addEventListener('mousemove',showVb,{passive:true});
  document.addEventListener('touchstart',showVb,{passive:true});
  // Start timer immediately
  _vbTimer=setTimeout(()=>vb.classList.add('hidden'),7000);
}

// VOLUME SLIDER
document.getElementById('volume-slider').addEventListener('input',function(){
  const vol=parseFloat(this.value);
  currentVolume=vol;
  if(vol>0){
    previousVolume=vol;
    isMuted=false;
  } else {
    isMuted=true;
  }
  if(icon){icon.innerHTML=isMuted
    ?'<path d="M11 5L6 9H2v6h4l5 4V5z"/><line x1="23" y1="9" x2="17" y2="15"/><line x1="17" y1="9" x2="23" y2="15"/>'
    :'<path d="M11 5L6 9H2v6h4l5 4V5z"/><path d="M19.07 4.93a10 10 0 0 1 0 14.14"/><path d="M15.54 8.46a5 5 0 0 1 0 7.07"/>';}
  applyVolume(currentVolume);
});

