function renderTrackSourceUI(){
  const src=document.getElementById('sp-source')?.value||'tracks';
  const sa=data.splashAudio||{};
  const el=document.getElementById('sp-source-ui');if(!el)return;
  if(src==='tracks'){
    el.innerHTML=`
      <div class="admin-section-title" style="margin-top:.8rem;">Playlist (Reihenfolge per Drag & Drop)</div>
      <div id="sp-track-list" style="margin-bottom:.5rem;"></div>
      <div style="display:flex;gap:.4rem;flex-wrap:wrap;align-items:flex-end;margin-top:.4rem;">
        <input id="sp-track-url" placeholder="Direkte MP3-URL (z.B. https://archive.org/.../track.mp3)" style="border:1px solid #ddd;padding:.38rem .6rem;font-size:.82rem;flex:1;min-width:200px;font-family:'Viaoda Libre',cursive;outline:none;"/>
        <input id="sp-track-label" placeholder="Titel (optional)" style="border:1px solid #ddd;padding:.38rem .6rem;font-size:.82rem;width:140px;font-family:'Viaoda Libre',cursive;outline:none;"/>
        <button class="admin-btn secondary small" onclick="addTrack()">+ Hinzufügen</button>
      </div>
      <p style="font-size:.68rem;color:#aaa;margin-top:.5rem;line-height:1.5;">💡 Lade deine MP3s auf <strong>archive.org</strong> hoch (kostenlos) und füge die direkte Datei-URL ein. Das ist die einzige Methode die zuverlässig auf iPhone/Android funktioniert.</p>`;
    renderTrackList();
  }else if(src==='soundcloud'){
    el.innerHTML=`<div class="admin-field"><label>SoundCloud Track-URL</label><input id="sp-sc" value="${escH(sa.soundcloudSrc||'')}" placeholder="https://soundcloud.com/user/track"/></div>`;
  }else{
    el.innerHTML=`<div class="admin-field"><label>Bandcamp Embed-src URL</label><input id="sp-bc" value="${escH(sa.bandcampSrc||'')}" placeholder="https://bandcamp.com/EmbeddedPlayer/..."/></div>`;
  }
}

let _tdi=null;
function renderTrackList(){
  const el=document.getElementById('sp-track-list');if(!el)return;
  const tracks=(data.splashAudio||{}).tracks||[];
  if(!tracks.length){el.innerHTML='<p style="font-size:.72rem;color:#aaa;margin-bottom:.3rem;">Noch keine Tracks.</p>';return;}
  el.innerHTML=tracks.map((t,i)=>`
    <div class="media-admin-item" draggable="true"
      ondragstart="_tdi=${i};event.dataTransfer.effectAllowed='move';setTimeout(()=>event.currentTarget.classList.add('dragging'),0)"
      ondragover="event.preventDefault();this.classList.add('drag-over')"
      ondrop="event.preventDefault();this.classList.remove('drag-over');if(_tdi!==null&&_tdi!==${i}){const a=data.splashAudio.tracks;const[it]=a.splice(_tdi,1);a.splice(${i},0,it);_tdi=null;document.querySelectorAll('.dragging').forEach(e=>e.classList.remove('dragging'));renderTrackList();showSaveNotice();}"
      ondragleave="this.classList.remove('drag-over')" style="cursor:grab;">
      <span style="color:#ccc;margin-right:.4rem;">⠿</span>
      <span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${i+1}. ${escH(t.label||t.url)}</span>
      <button class="admin-btn danger small" onclick="removeTrack(${i})">✕</button>
    </div>`).join('');
}
function addTrack(){
  const url=document.getElementById('sp-track-url').value.trim();
  const label=document.getElementById('sp-track-label').value.trim();
  if(!url){alert('Bitte URL eingeben.');return;}
  if(!data.splashAudio)data.splashAudio={};
  if(!data.splashAudio.tracks)data.splashAudio.tracks=[];
  data.splashAudio.tracks.push({url,label:label||url.split('/').pop()});
  document.getElementById('sp-track-url').value='';
  document.getElementById('sp-track-label').value='';
  renderTrackList();showSaveNotice();
}
function removeTrack(i){
  if(!data.splashAudio||!data.splashAudio.tracks)return;
  data.splashAudio.tracks.splice(i,1);renderTrackList();showSaveNotice();
}

function saveSplash(){
  data.splashImg=(document.getElementById('sp-img')?.value||'').trim();
  if(!data.splashAudio)data.splashAudio={};
  data.splashAudio.active=document.getElementById('sp-active').value==='1';
  const src=document.getElementById('sp-source').value;
  data.splashAudio.source=src;
  if(src==='soundcloud')data.splashAudio.soundcloudSrc=(document.getElementById('sp-sc')?.value||'').trim();
  if(src==='bandcamp')data.splashAudio.bandcampSrc=(document.getElementById('sp-bc')?.value||'').trim();
  showSaveNotice();
}

function updateBgState(){
  const hasBg=['section-bg','project-bg','home-bg','termine-bg','bio-bg','kontakt-bg']
    .some(id=>document.getElementById(id)?.style.display==='block');
  document.body.classList.toggle('has-bg',hasBg);
  window.dispatchEvent(new Event('scroll'));
}

// HEADER SCROLL TRANSPARENCY — throttled via requestAnimationFrame
let _scrollRAF=false;
window.addEventListener('scroll',()=>{
  if(_scrollRAF)return;
  _scrollRAF=true;
  requestAnimationFrame(()=>{
    _scrollRAF=false;
    const header=document.querySelector('header');
    if(!header)return;
    const hasBg=['section-bg','project-bg','home-bg','termine-bg','bio-bg','kontakt-bg']
      .some(id=>document.getElementById(id)?.style.display==='block');
    if(!hasBg){header.style.opacity='1';header.classList.remove('scrolled');return;}
    const scrollY=window.scrollY;
    const fadeStart=20,fadeEnd=70;
    if(scrollY<=fadeStart){
      header.style.opacity='1';header.classList.remove('scrolled');
    }else if(scrollY>=fadeEnd){
      header.style.opacity='0';header.classList.add('scrolled');
    }else{
      const alpha=1-(scrollY-fadeStart)/(fadeEnd-fadeStart);
      header.style.opacity=String(alpha);header.classList.add('scrolled');
    }
  });
},{ passive:true });

// SOUNDCLOUD PRELOAD — load iframe silently at page start so iOS allows playback on click
function preloadSoundcloudIfNeeded(){
  const sa=data.splashAudio||{};
  if(!sa.active||sa.source!=='soundcloud'||!sa.soundcloudSrc)return;
  const existing=document.getElementById('splash-audio-frame');
  if(existing)return;
  let scUrl=sa.soundcloudSrc;
  if(!scUrl.includes('w.soundcloud.com')){
    scUrl='https://w.soundcloud.com/player/?url='+encodeURIComponent(scUrl)+'&auto_play=false&hide_related=true&show_comments=false&show_user=true&show_reposts=false&show_teaser=false';
  }else{
    scUrl=scUrl.replace('auto_play=true','auto_play=false');
  }
  const iframe=document.createElement('iframe');
  iframe.id='splash-audio-frame';
  iframe.style.cssText='display:none;position:absolute;width:0;height:0;';
  iframe.allow='autoplay';
  iframe.src=scUrl;
  document.body.appendChild(iframe);
  // Give iframe time to load, then on click we just trigger play via postMessage
  iframe.addEventListener('load',()=>{
    // Preloaded and ready — playback triggered by user click in buildSplashAudioPlayer
  });
}
function adjustMainPadding(){
  const header=document.querySelector('header');
  const main=document.querySelector('main');
  if(!header||!main)return;
  main.style.paddingTop=(header.offsetHeight+16)+'px';
}

function init(){
  data=migrateData(data);
  renderAll();
  renderHomeBg();
  document.querySelectorAll('.lang-btn').forEach(b=>b.classList.toggle('active',b.textContent===lang.toUpperCase()));
  initSplash();
  if(window.location.hash==='#backend'){
    history.replaceState({},'',window.location.pathname);
    openBackend();
  }else{
    history.replaceState({},'',window.location.pathname);
  }
  adjustMainPadding();
  window.addEventListener('resize',adjustMainPadding);
}
init();